 const Main=() =>{
            return (
              <>
                <div className="main_container">
                  <div className="card_wrapper">
                    <PaginatedItems itemsPerPage={3} />
                      variant="outlined"
                      shape="rounded"
                      itemsPerPage={3}
                    />
                  </div>
